import jwt
from datetime import datetime, timedelta

def generate_jwt(user_id, role):
    # Define key for signing token 
    SECRET_KEY = 'YOUR_SECRET_KEY'
    
    # Prepare payload with user data and an expiration date (1 hour from now)
    payload = {
        "user_id": user_id,
        "role": role,
        "exp": datetime.utcnow() + timedelta(hours=1)
    }
    
    # Generate JWT with HS256 algorithm and return it
    jwt_token = jwt.encode(payload, SECRET_KEY, algorithm='HS256')
    return jwt_token